from transformers import AutoTokenizer

tokenizer = AutoTokenizer.from_pretrained("meta-llama/Meta-Llama-3-8B-Instruct")
print(tokenizer.chat_template)
# Output (excerpt):
# {%- for message in messages %}
#   {%- if message.role == 'system' %}
#     {{- '<|start_header_id|>system<|end_header_id|>\n\n' + message.content + '<|eot_id|>' }}
#   {%- elif message.role == 'user' %}
#     {{- '<|start_header_id|>user<|end_header_id|>\n\n' + message.content + '<|eot_id|>' }}
#   {%- elif message.role == 'assistant' %}
#     {{- '<|start_header_id|>assistant<|end_header_id|>\n\n' + message.content + '<|eot_id|>' }}
#   {%- endif %}
# {%- endfor %}

# Modify the template to always include a fixed system prompt if none is given
custom_template = """
{%- if not messages[0].role == 'system' %}
  {{- '<|start_header_id|>system<|end_header_id|>\n\nYou are a coding assistant.<|eot_id|>' }}
{%- endif %}
{%- for message in messages %}
  {{- '<|start_header_id|>' + message.role + '<|end_header_id|>\n\n' + message.content + '<|eot_id|>' }}
{%- endfor %}
{%- if add_generation_prompt %}
  {{- '<|start_header_id|>assistant<|end_header_id|>\n\n' }}
{%- endif %}
"""

tokenizer.chat_template = custom_template.strip()
tokenizer.save_pretrained("./my-tokenizer")

tool_messages = [
    {"role": "system", "content": "You are a helpful assistant with access to tools."},
    {"role": "user",   "content": "What is the weather in Paris?"},
    {
        "role": "assistant",
        "content": None,
        "tool_calls": [{
            "id": "call_abc123",
            "type": "function",
            "function": {
                "name": "get_weather",
                "arguments": '{"location": "Paris, France"}',
            },
        }],
    },
    {
        "role": "tool",
        "tool_call_id": "call_abc123",
        "content": '{"temperature": 18, "condition": "partly cloudy"}',
    },
    {"role": "assistant", "content": "The weather in Paris is 18 °C and partly cloudy."},
]

formatted = tokenizer.apply_chat_template(
    tool_messages,
    tools=[{"type": "function", "function": {"name": "get_weather", ...}}],
    tokenize=False,
)
